import{_ as t,o,c as e,a0 as r}from"./chunks/framework.jwovEGr5.js";const i="/assets/003_image_Ehpebt4Eso.Dw6FFomg.png",s="/assets/005_image_CMvYbYWFOo.jYDDZzx9.png",d="/assets/010_image_TmYPbu7Ibo.Ctjv1mqR.png",l="/assets/013_image_MMIXbZJafo.B9_LWfGr.png",n="/assets/015_image_WZrBbbWono.C1LiVhfP.png",h="/assets/017_image_Qt1gbb7J3o.N_vE_aca.png",k=JSON.parse('{"title":"第 2 章 下载、安装、登录与更新","description":"","frontmatter":{},"headers":[],"relativePath":"p1/02.md","filePath":"p1/02.md"}'),c={name:"p1/02.md"};function p(u,a,m,g,b,_){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="第-2-章-下载、安装、登录与更新" tabindex="-1">第 2 章 下载、安装、登录与更新 <a class="header-anchor" href="#第-2-章-下载、安装、登录与更新" aria-label="Permalink to &quot;第 2 章 下载、安装、登录与更新&quot;">​</a></h1><blockquote><p>本章综合蓝皮书第 2 章与橙皮书「安装前准备」「客户端安装」「首次启动与登录」等内容。</p></blockquote><h2 id="workbuddy-下载" tabindex="-1">WorkBuddy 下载 <a class="header-anchor" href="#workbuddy-下载" aria-label="Permalink to &quot;WorkBuddy 下载&quot;">​</a></h2><p>下载 WorkBuddy，访问官网地址（<a href="https://www.codebuddy.cn/work/%EF%BC%89%EF%BC%8C%E9%80%89%E6%8B%A9" target="_blank" rel="noreferrer">https://www.codebuddy.cn/work/），选择</a> WorkBuddy，点击&quot;下载 WorkBuddy&quot;即可下载。</p><p>网站会自动检查你当前设备，判断你是什么版本——Mac ARM64、Mac x64 或者 Windows x64。</p><p><em><strong>切记：从官方入口进入下载，不从网盘或不明镜像获取安装包。</strong></em></p><h2 id="安装前准备" tabindex="-1">安装前准备 <a class="header-anchor" href="#安装前准备" aria-label="Permalink to &quot;安装前准备&quot;">​</a></h2><h3 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>系统</th><th>最低版本</th><th>其他要求</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>12.0+</td><td>Apple 芯片或 Intel，约 200MB 磁盘空间</td></tr><tr><td><strong>Windows</strong></td><td>10+</td><td>.NET 运行时（精简版 Windows 需手动安装），约 200MB</td></tr><tr><td><strong>Linux</strong></td><td>主流发行版</td><td>见官方文档</td></tr></tbody></table><h3 id="账号准备" tabindex="-1">账号准备 <a class="header-anchor" href="#账号准备" aria-label="Permalink to &quot;账号准备&quot;">​</a></h3><ul><li>WorkBuddy 账号（微信 / 企业微信 / QQ 登录）</li><li>新用户首次登录赠送 <strong>5000 Credits</strong> 免费额度</li><li>每日签到可额外领取积分</li></ul><blockquote><p>⚠️ <strong>重要</strong>：建议登录后第一时间修改<strong>默认工作空间存储路径</strong>。默认路径在 C 盘，长期使用会导致 C 盘空间不足。修改路径：点击头像 → 设置 → 系统设置 → 修改工作空间存储路径。</p></blockquote><h2 id="windows-安装步骤" tabindex="-1">Windows 安装步骤 <a class="header-anchor" href="#windows-安装步骤" aria-label="Permalink to &quot;Windows 安装步骤&quot;">​</a></h2><ol><li>访问官网下载 Windows 安装包（约 150-180MB）</li><li>找到下载的 <code>WorkBuddySetup.exe</code>，<strong>右键 → 以管理员身份运行</strong>（这是插件正常安装的关键）</li><li>建议使用默认安装路径（<code>C:\\Program Files\\Tencent\\WorkBuddy</code>），避免中文路径引发兼容性问题</li><li>安装完成后桌面自动生成快捷方式</li></ol><p><strong>📸 Windows 安装截图</strong></p><p><img src="'+i+'" alt=""></p><p><img src="'+s+'" alt=""></p><h2 id="macos-安装步骤" tabindex="-1">macOS 安装步骤 <a class="header-anchor" href="#macos-安装步骤" aria-label="Permalink to &quot;macOS 安装步骤&quot;">​</a></h2><ol><li>访问官网下载 macOS 安装包（<code>.dmg</code> 文件）</li><li>双击 <code>.dmg</code> 文件，将 WorkBuddy 图标拖入&quot;应用程序&quot;文件夹</li><li>若提示&quot;无法打开，因为 Apple 无法检查其是否包含恶意软件&quot;： <ul><li>前往「系统设置 → 隐私与安全」</li><li>在&quot;安全性&quot;栏点击「仍要打开」</li></ul></li><li>完成系统授权后重新打开即可</li></ol><p><strong>📸 macOS 安装截图</strong></p><p><img src="'+d+'" alt=""></p><h2 id="首次启动与登录" tabindex="-1">首次启动与登录 <a class="header-anchor" href="#首次启动与登录" aria-label="Permalink to &quot;首次启动与登录&quot;">​</a></h2><ol><li>双击打开客户端，进入登录界面</li><li>使用微信 / 企业微信 / QQ <strong>扫码登录</strong>（无需手动输入账号密码）</li><li>首次登录后，系统自动发放新手权益（5000 Credits + 10 款常用技能包，有效期 30 天）</li></ol><p><strong>📸 登录界面</strong></p><p><img src="'+l+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><em>PS：若公司电脑禁止安装软件，不要绕过终端安全策略，应联系 IT 管理员确认白名单或企业部署方式。</em></p><h2 id="更新" tabindex="-1">更新 <a class="header-anchor" href="#更新" aria-label="Permalink to &quot;更新&quot;">​</a></h2><p>点击左下角个人中心，选择&quot;检查更新&quot;，检查是否有新版本，若有新版本，可更新</p><p><strong>📸 更新界面</strong></p><p><img src="'+h+'" alt=""></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="安装包打不开或提示损坏" tabindex="-1">安装包打不开或提示损坏 <a class="header-anchor" href="#安装包打不开或提示损坏" aria-label="Permalink to &quot;安装包打不开或提示损坏&quot;">​</a></h3><p>先删除安装包并从官网重新下载，核对系统和芯片版本。仍失败时记录系统版本、安装包名和报错截图，通过官方反馈渠道处理，不要随意关闭系统安全功能。</p><h3 id="登录后没有反应" tabindex="-1">登录后没有反应 <a class="header-anchor" href="#登录后没有反应" aria-label="Permalink to &quot;登录后没有反应&quot;">​</a></h3><p>检查默认浏览器是否拦截登录回跳、网络代理是否影响认证、系统时间是否准确。退出应用后重试，并保留日志与截图。</p><h3 id="无法读取或写入文件" tabindex="-1">无法读取或写入文件 <a class="header-anchor" href="#无法读取或写入文件" aria-label="Permalink to &quot;无法读取或写入文件&quot;">​</a></h3><p>确认任务选择的工作目录是否正确、系统是否授予对应目录权限、文件是否被其他程序锁定。先用一个空白文本文件测试，不要直接拿重要文件反复试错。</p><h3 id="更新前要不要备份" tabindex="-1">更新前要不要备份 <a class="header-anchor" href="#更新前要不要备份" aria-label="Permalink to &quot;更新前要不要备份&quot;">​</a></h3><p>应用更新一般不应修改工作文件，但长期项目仍应把输入、产物、配置和自定义 Skill 纳入版本管理或定期备份。</p><hr><p><em>（你可以在本章后面插入 <code>![](/assets/your-screenshot.png)</code> 来添加你自己的截图。）</em></p>',42)])])}const f=t(c,[["render",p]]);export{k as __pageData,f as default};
